import{_ as a,o as t,c as i,a2 as r}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"ADR-0004: Provider-Neutral Assistant and Web Search","description":"","frontmatter":{},"headers":[],"relativePath":"sovereign-os/adrs/0004-provider-neutral-assistant-and-web-search.md","filePath":"sovereign-os/adrs/0004-provider-neutral-assistant-and-web-search.md"}'),n={name:"sovereign-os/adrs/0004-provider-neutral-assistant-and-web-search.md"};function o(l,e,s,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="adr-0004-provider-neutral-assistant-and-web-search" tabindex="-1">ADR-0004: Provider-Neutral Assistant and Web Search <a class="header-anchor" href="#adr-0004-provider-neutral-assistant-and-web-search" aria-label="Permalink to &quot;ADR-0004: Provider-Neutral Assistant and Web Search&quot;">​</a></h1><p><strong>Status:</strong> Accepted</p><p><strong>Date:</strong> 2026-07-22</p><p><strong>Decision owner:</strong> Project creator</p><p><strong>Related milestone:</strong> <a href="./../roadmap/01-2-local-conversation-capabilities.html">Milestone 01.2</a></p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Sovereign OS needs local conversation, capability orchestration, current web information, and later home automation. Ollama, llama.cpp, Open WebUI, and SearXNG can provide useful parts of that system, but making any third-party product the Sovereign contract would couple identity, data, updates, permissions, or user experience to an implementation that may change.</p><p>Self-hosting an inference runner keeps prompts local. Self-hosting a metasearch service has a different privacy boundary: SearXNG still submits queries to its configured upstream engines and result pages remain external content.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><ul><li>Sovereign owns a normalized inference-provider contract and the model manifest, verification, storage, activation, and rollback lifecycle.</li><li>llama.cpp and Ollama will be benchmarked behind that contract on the target Raspberry Pi. The initial runner and model will be recorded separately after evidence is available.</li><li>Sovereign owns the product conversation interface. Open WebUI may be an optional development/evaluation service but is not the product shell.</li><li>Models may only propose registered capability calls. A deterministic Sovereign executor validates and authorizes every call.</li><li>SearXNG is the initial replaceable provider for <code>web.search</code>.</li><li><code>web.search</code> and constrained <code>web.fetch</code> are separate capabilities. The model receives no generic network tool.</li><li>Web search is explicitly enabled or approved, visibly communicates the query and external boundary, and must not silently incorporate private household context.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>The runner, model, search provider, and development UI remain replaceable.</li><li>Sovereign can enforce one privacy and capability policy across local and optional remote providers.</li><li>Model artifacts can participate in signed releases and reproducible updates.</li><li>Search citations and external communication can be represented directly in the product experience.</li><li>Home Assistant and future integrations can reuse the same executor instead of granting the model direct service access.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Sovereign must implement adapters, model lifecycle, and a minimal conversation interface instead of delegating those product responsibilities to Ollama or Open WebUI.</li><li>Model/tool compatibility requires a maintained evaluation corpus.</li><li>SearXNG requires operation and upstream-engine maintenance and cannot promise that search queries stay local.</li><li>A constrained fetcher requires SSRF, content-size, timeout, redirect, and prompt-injection controls.</li></ul><h2 id="required-follow-up" tabindex="-1">Required Follow-up <a class="header-anchor" href="#required-follow-up" aria-label="Permalink to &quot;Required Follow-up&quot;">​</a></h2><ul><li>Define the inference and model-manifest contracts in an RFC.</li><li>Benchmark llama.cpp and Ollama on the Raspberry Pi 5.</li><li>Define capability schemas, authorization, confirmation, and auditing.</li><li>Document SearXNG deployment, upstream configuration, retention, and failure behavior.</li><li>Update the data inventory and threat model before processing real conversations or external content.</li><li>Record the selected runner and initial model in a later ADR.</li></ul><h2 id="rejected-alternatives" tabindex="-1">Rejected Alternatives <a class="header-anchor" href="#rejected-alternatives" aria-label="Permalink to &quot;Rejected Alternatives&quot;">​</a></h2><h3 id="make-ollama-the-product-api" tabindex="-1">Make Ollama the product API <a class="header-anchor" href="#make-ollama-the-product-api" aria-label="Permalink to &quot;Make Ollama the product API&quot;">​</a></h3><p>Ollama is useful operationally but its API and model lifecycle would become a platform dependency rather than a replaceable implementation.</p><h3 id="use-open-webui-as-the-sovereign-interface" tabindex="-1">Use Open WebUI as the Sovereign interface <a class="header-anchor" href="#use-open-webui-as-the-sovereign-interface" aria-label="Permalink to &quot;Use Open WebUI as the Sovereign interface&quot;">​</a></h3><p>This would accelerate a demo but duplicate or displace Sovereign identity, permission, capability, citation, and privacy responsibilities.</p><h3 id="use-a-hosted-search-api-by-default" tabindex="-1">Use a hosted search API by default <a class="header-anchor" href="#use-a-hosted-search-api-by-default" aria-label="Permalink to &quot;Use a hosted search API by default&quot;">​</a></h3><p>It would introduce a mandatory third-party processor for user queries and conflict with the local-first default.</p><h3 id="give-the-model-general-outbound-http-access" tabindex="-1">Give the model general outbound HTTP access <a class="header-anchor" href="#give-the-model-general-outbound-http-access" aria-label="Permalink to &quot;Give the model general outbound HTTP access&quot;">​</a></h3><p>This would make authorization, private-context control, SSRF protection, and auditability substantially weaker than explicit typed capabilities.</p>',26)])])}const m=a(n,[["render",o]]);export{u as __pageData,m as default};
